import type { int } from "@tsonic/core/types.js";

type Ok<T> = {
  success: true;
  data: T;
};

type Err<E> = {
  success: false;
  error: E;
};

export type Result<T, E> = Ok<T> | Err<E>;

export class Channel {
  MessageRetentionDays?: int;
}

export function getChannel(): Result<Channel, string> {
  return {
    success: true,
    data: new Channel(),
  };
}
